function summarizeUsers(users) {
  let activeCount = 0;
  let totalAge = 0;
  for (let i = 0; i < users.length; i++) {
    if (users[i].isActive) {
      activeCount++;
      totalAge += users[i].age;
    }
  }
  let averageAge = 0;
  if (activeCount > 0) {
    averageAge = totalAge / activeCount;
  }
  return { activeCount, averageAge };
}

